-- ============================================================
-- Greenie Seed Data (Development)
-- Mirrors the fake repository data so the app works identically
-- after swapping to Supabase repositories.
--
-- Paste into Supabase SQL Editor and run AFTER schema.sql.
-- Safe to re-run: uses INSERT ... ON CONFLICT DO NOTHING.
-- ============================================================

-- Deterministic UUIDs so foreign keys stay consistent.
-- Pattern: 00000000-0000-0000-<domain>-<sequence>
--   members  → domain 0001  (member-1 .. member-14)
--   courses  → domain 0002  (course-1 .. course-3)
--   leagues  → domain 0003  (league-1 .. league-2)
--   teams    → domain 0004  (team-1 .. team-7)
--   rounds   → domain 0005  (round-1 .. round-6)
--   matchups → domain 0006  (18 matchups across 6 rounds)


-- ============================================================
-- MEMBERS
-- ============================================================
on conflict do nothing;


